\par \pard\fi0\li0\qj\ri0\sb0\sa0\itap0 (172\plain \f1\super\lang1033\fs24 va\plain \f1\lang1033\fs24 -173\plain \f1\super\lang1033\fs24 ra\plain \f1\lang1033\fs24 ) \plain \f1\i\lang1033\fs24 >\plain \f1\b\i\lang1033\fs24 In Pasca\plain \f1\i\lang1033\fs24  hymnus<\plain \f1\lang1033\fs24  (172\plain \f1\super\lang1033\fs24 va-vb\plain \f1\lang1033\fs24 )\plain \f1\i\lang1033\fs24  >U<{\field{\*\fldinst HYPERLINK "hida://5650[11].5666l/?u"}{\fldrslt \plain \f1\i\lang1033\fs24\chcbpat17 ita}}\plain \f1\i\lang1033\fs24  sanctorum decus \plain \f1\lang1033\fs24 [sonst: deus]\plain \f1\i\lang1033\fs24  angelorum, / uita cunctorum pariter piorum, ...\plain \f1\lang1033\fs24  ({\field{\*\fldinst HYPERLINK "hida://bezlit[1].8330/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 AH 51, Nr. 85}}\plain \f1\lang1033\fs24 ), (172\plain \f1\super\lang1033\fs24 vb\plain \f1\lang1033\fs24 -173\plain \f1\super\lang1033\fs24 ra\plain \f1\lang1033\fs24 ) \plain \f1\i\lang1033\fs24 >Ad Completorium hymnus< >A<{\field{\*\fldinst HYPERLINK "hida://5650[12].5666l/?u"}{\fldrslt \plain \f1\i\lang1033\fs24\chcbpat17 D cenam agni prouidi, / et stolis albis candidi}}\plain \f1\i\lang1033\fs24 , ...\plain \f1\lang1033\fs24  ({\field{\*\fldinst HYPERLINK "hida://bezlit[1].8330/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 AH 51, Nr. 83}}\plain \f1\lang1033\fs24 , in doppelter Notation); \plain \f1\lang1033\fs20 Offizium s. o. 78\plain \f1\super\lang1033\fs20 r\plain \f1\lang1033\fs20 -79\plain \f1\super\lang1033\fs20 r\plain \f1\lang1033\fs20 ; Sequenz s. u. 233\plain \f1\super\lang1033\fs20 r\plain \f1\lang1033\fs20 -235\plain \f1\super\lang1033\fs20 r\plain \f1\lang1033\fs20 ;
\par \pard\fi0\li0\qj\ri0\sb0\sa0\itap0 \plain \f1\lang1033\fs24 (173\plain \f1\super\lang1033\fs24 ra-va\plain \f1\lang1033\fs24 ) \plain \f1\i\lang1033\fs24 >Hymnus \plain \f1\b\i\lang1033\fs24 de lancea domini\plain \f1\i\lang1033\fs24 <\plain \f1\lang1033\fs24  (Festum lanceae et clavorum domini, Feria VI. post Domin. Quasimodogeniti), (173\plain \f1\super\lang1033\fs24 ra-rb\plain \f1\lang1033\fs24 ) [In 1. Vesperis:] \plain \f1\i\lang1033\fs24 >P<{\field{\*\fldinst HYPERLINK "hida://5650[13].5666l/?u"}{\fldrslt \plain \f1\i\lang1033\fs24\chcbpat17 Ange, lingua, gloriose / lancee preconium}}\plain \f1\i\lang1033\fs24 , ...\plain \f1\lang1033\fs24  ({\field{\*\fldinst HYPERLINK "hida://bezlit[4].8330/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 AH 52, Nr. 6}}\plain \f1\lang1033\fs24 ), (173\plain \f1\super\lang1033\fs24 rb-va\plain \f1\lang1033\fs24 )\plain \f1\i\lang1033\fs24  >Ad completorium<\plain \f1\lang1033\fs24  \plain \f1\i\lang1033\fs24 >E<{\field{\*\fldinst HYPERLINK "hida://5650[14].5666l/?u"}{\fldrslt \plain \f1\i\lang1033\fs24\chcbpat17 Terna Christi munera / nos sacient perhenniter}}\plain \f1\i\lang1033\fs24  ... \plain \f1\lang1033\fs24 ({\field{\*\fldinst HYPERLINK "hida://bezlit[4].8330/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 AH 52, Nr. 7}}\plain \f1\lang1033\fs24 );
\par \pard\fi0\li0\qj\ri0\sb0\sa0\itap0 \plain \f1\lang1033\fs20 Das Festum lanceae et clavorum domini wurde auf Bitten {\field{\*\fldinst HYPERLINK "hida://bezper[3].4100/?u"}{\fldrslt \plain \f1\lang1033\fs20\chcbpat17 Kaiser Karls IV}}\plain \f1\lang1033\fs20 . am 13. Februar 1353 durch die Bulle \u8222 \'84Redemptor noster\ldblquote  {\field{\*\fldinst HYPERLINK "hida://bezper[4].4100/?u"}{\fldrslt \plain \f1\lang1033\fs20\chcbpat17 Papst Innozenz\lquote  IV.}}\plain \f1\lang1033\fs20  im gesamten r\u246 \'f6m. Reich dt. Nation eingef\u252 \'fchrt, um die zu den Reichsinsignien geh\u246 \'f6renden Heiligt\u252 \'fcmer zu verehren, vgl. F. \plain \f1\scaps\lang1033\fs20 Falk\plain \f1\lang1033\fs20 , Die Einf\u252 \'fchrung des Festum lanceae et clavorum sive armorum Christi, in: Der Katholik, Zeitschrift f\u252 \'fcr katholische Wissenschaft und kirchliches Leben NF 2 (1883), S. 544-546. Nach AH 52, S. 8, wurde der Ebf. von {\field{\*\fldinst HYPERLINK "hida://bezwrk[1].6923/?u"}{\fldrslt \plain \f1\lang1033\fs20\chcbpat17 Mainz}}\plain \f1\lang1033\fs20  vom Papst beauftragt, daf\u252 \'fcr zu sorgen, dass ein vom Kaiser zu bestimmender Priester ein passendes Offizium zu diesem Fest anfertigte. Wahrscheinlich handelt es sich beim Verfasser um einen b\u246 \'f6hmischen Landmann des Kaisers, die beiden Hymnen sind nach AH, ebd., verst\u228 \'e4rkt in b\u246 \'f6hmischen Textzeugen belegt. Mit einer Urkunde vom 29.10.1492 befahl der Mei\u223 \'dfner Bf. {\field{\*\fldinst HYPERLINK "hida://bezper[5].4100/?u"}{\fldrslt \plain \f1\lang1033\fs20\chcbpat17 Johann IV.}}\plain \f1\lang1033\fs20  von Salhausen der gesamten Geistlichkeit seiner Di\u246 \'f6zese, das Fest der hl. Lanze in seiner Di\u246 \'f6zese j\u228 \'e4hrlich am Freitag nach Quasimodogeniti \u8222 \'84veluti chori festum cum sua propria historia et missae officio\ldblquote  zu begehen, zugleich verband er damit einen vierzigt\u228 \'e4gigen Ablass, als Initiatorin f\u252 \'fcr die Einf\u252 \'fchrung des Festes wird ausdr\u252 \'fccklich {\field{\*\fldinst HYPERLINK "hida://bezper[6].4100/?u"}{\fldrslt \plain \f1\lang1033\fs20\chcbpat17 Herzogin Sidonia von Sachsen}}\plain \f1\lang1033\fs20  (1449-1510) genannt, vgl. UB Hochstift Mei\u223 \'dfen, Bd. 3, Nr. 1285, S. 291; \plain \f1\scaps\lang1033\fs20 Pasig\plain \f1\lang1033\fs20 , Johannes VI., S. 118f. Zur zugeh\u246 \'f6rigen Sequenz und zum Offizium s. u. 251\plain \f1\super\lang1033\fs20 v\plain \f1\lang1033\fs20 -252\plain \f1\super\lang1033\fs20 r\plain \f1\lang1033\fs20  und 268\plain \f1\super\lang1033\fs20 v\plain \f1\lang1033\fs20 .
\par \pard\fi0\li0\qj\ri0\sb0\sa0\itap0 \plain \f1\lang1033\fs24 (173\plain \f1\super\lang1033\fs24 va\plain \f1\lang1033\fs24 -174\plain \f1\super\lang1033\fs24 ra\plain \f1\lang1033\fs24 ) \plain \f1\i\lang1033\fs24 >Hymnus \plain \f1\b\i\lang1033\fs24 de Ascensione domini\plain \f1\i\lang1033\fs24 <\plain \f1\lang1033\fs24 , (173\plain \f1\super\lang1033\fs24 va-vb\plain \f1\lang1033\fs24 ) [In 1. Vesperis:] \plain \f1\i\lang1033\fs24 >F<{\field{\*\fldinst HYPERLINK "hida://5650[15].5666l/?u"}{\fldrslt \plain \f1\i\lang1033\fs24\chcbpat17 Estum nunc celebre magnaque gaudia / compellunt animos carmina promere}}\plain \f1\i\lang1033\fs24 , ...\plain \f1\lang1033\fs24  ({\field{\*\fldinst HYPERLINK "hida://bezlit[2].8330/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 AH 50, Nr. 148}}\plain \f1\lang1033\fs24 , Autor: {\field{\*\fldinst HYPERLINK "hida://bezper[7].4100/?u"}{\fldrslt \plain \f1\scaps\lang1033\fs24\chcbpat17 Hrabanus Maurus}}\plain \f1\lang1033\fs24 ), (173\plain \f1\super\lang1033\fs24 vb\plain \f1\lang1033\fs24 -174\plain \f1\super\lang1033\fs24 ra\plain \f1\lang1033\fs24 ) \plain \f1\i\lang1033\fs24 >Ad completorium< >I<{\field{\*\fldinst HYPERLINK "hida://5650[16].5666l/?u"}{\fldrslt \plain \f1\i\lang1033\fs24\chcbpat17 Hesu, nostra redemptio, / amor et desiderium}}\plain \f1\i\lang1033\fs24 , ...\plain \f1\lang1033\fs24  ({\field{\*\fldinst HYPERLINK "hida://bezlit[1].8330/?u"}{\fldrslt \plain \f1\lang1033\fs24\chcbpat17 AH 51, Nr. 89}}\plain \f1\lang1033\fs24 ); \plain \f1\lang1033\fs20 Offizium s. o. 89\plain \f1\super\lang1033\fs20 r\plain \f1\lang1033\fs20 -90\plain \f1\super\lang1033\fs20 r\plain \f1\lang1033\fs20 , Sequenz s. u. 235\plain \f1\super\lang1033\fs20 r\plain \f1\lang1033\fs20 -236\plain \f1\super\lang1033\fs20 r\plain \f1\lang1033\fs20 ;
